import type { Song, Artist, Discography, Performance, Setlist } from '@/types';

// Build-time snapshot of the dataset. Generated by scripts/fetch-snapshot.ts
// (which pulls GET /data from the Cloud Run data API) and gitignored — it is a
// build artifact, never committed, so the repo never carries stale data.
import snapshot from '@/data/snapshot.json';

export interface SeriesInfo {
  id: string;
  name: string;
  color: string;
}

// Provenance of the dataset, stamped by the daily refresh job
// (pipeline/run-refresh.ts) and carried through the /data payload.
export interface BuildInfo {
  generatedAt?: string;
  counts?: Record<string, number>;
}

// The full dataset the app needs, sourced either from the data API (DB-backed)
// at runtime or the bundled snapshot below as the first-paint / offline fallback.
export interface Dataset {
  songs: Song[];
  artists: Artist[];
  discographies: Discography[];
  seriesInfo: SeriesInfo[];
  seriesNames: Record<string, string>;
  performances: Performance[];
  setlists: Record<string, Setlist>;
  build: BuildInfo | null;
}

// Coerce an arbitrary /data payload (live API or bundled snapshot) into a
// Dataset, defaulting any missing field to empty.
export function toDataset(raw: unknown): Dataset {
  const d = (raw ?? {}) as Partial<Dataset>;
  return {
    songs: d.songs ?? [],
    artists: d.artists ?? [],
    discographies: d.discographies ?? [],
    seriesInfo: d.seriesInfo ?? [],
    seriesNames: d.seriesNames ?? {},
    performances: d.performances ?? [],
    setlists: d.setlists ?? {},
    build: d.build ?? null,
  };
}

// Bundled snapshot — src/data/snapshot.json, baked in at build time. Used for
// instant first paint and as the fallback when the live API is unreachable.
export const bundledDataset: Dataset = toDataset(snapshot as unknown);
